#include <iostream>
#include <sstream>
#include <string>
#include <cmath>

class Complex {
public:
    double real;
    double imaginary;

    Complex(double r = 0.0, double i = 0.0) : real(r), imaginary(i) {}
};

std::ostream& operator<<(std::ostream& os, const Complex& c) {
    if (c.imaginary == 0) {
        os << c.real;
    } else if (c.real == 0) {
        os << c.imaginary << "i";
    } else {
        os << c.real;
        if (c.imaginary > 0) {
            os << " + " << c.imaginary << "i";
        } else {
            os << " - " << std::abs(c.imaginary) << "i";
        }
    }
    return os;
}

int main() {
    Complex c1(3, 4); std::cout << c1 << std::endl;
    Complex c2(5, -2); std::cout << c2 << std::endl;
    Complex c3(0, 7); std::cout << c3 << std::endl;
    Complex c4(6, 0); std::cout << c4 << std::endl;
    Complex c5(-1, -1); std::cout << c5 << std::endl;
    Complex c6(0, 0); std::cout << c6 << std::endl;
    Complex c7(1, 1); std::cout << c7 << std::endl;
    Complex c8(1, -1); std::cout << c8 << std::endl;
    Complex c9(-1, 1); std::cout << c9 << std::endl;
    return 0;
}
